type Grid = number[][];

const countNeighbors = (grid: Grid, row: number, col: number): number => {
  let count = 0;
  for (let r = row - 1; r <= row + 1; r++) {
    for (let c = col - 1; c <= col + 1; c++) {
      if (r === row && c === col) continue;
      if (r >= 0 && r < grid.length && c >= 0 && c < grid[r].length) {
        count += grid[r][c];
      }
    }
  }
  return count;
};

export function nextGeneration(grid: Grid): Grid {
  if (grid.length === 0) return [];

  const next: Grid = grid.map((row, r) =>
    row.map((cell, c) => {
      const neighbors = countNeighbors(grid, r, c);
      if (cell === 1 && (neighbors === 2 || neighbors === 3)) return 1;
      if (cell === 0 && neighbors === 3) return 1;
      return 0;
    })
  );

  const hasLiveCells = next.some(row => row.some(cell => cell === 1));
  if (!hasLiveCells) return [];

  return next;
}
